checks.expected:
.launch-shell :is(img, video) {
  display: block;
  max-inline-size: 100%;
  block-size: auto;
}

@media (width >= 60rem) {
  .launch-hero {
    display: grid;
    grid-template-columns: minmax(0, 1fr) minmax(18rem, 1fr);
    gap: 2rem;
    align-items: center;
  }
}

.evidence-cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 16rem), 1fr));
  gap: 1rem;
}

.launch-shell :is(a, button, input):focus-visible {
  outline: 0.2rem solid var(--launch-focus);
  outline-offset: 0.2rem;
}

@media print {
  .interest-form, .product-demo {
    display: none;
  }
  .launch-shell {
    color: #000000;
    background: #ffffff;
  }
  .evidence-card {
    break-inside: avoid;
  }
}
